# ≡KT module  java/com/sara/workoutforlife/data/model/PathDefinition.kt  ->  PathDefinition.py
# connects(1deg): FocusArea, GoalType, PathCategory, PathLever, displayName

class PathCategory:
    """≡KT  enum class PathCategory  -> enum class (exact)
    attrs (6/6): displayName, MENTAL_HEALTH, STRENGTH, FULL_BODY, LEARNING, SELF_DIRECTED
    connects(1deg): displayName
    """
    def __init__(self, displayName):
        self.displayName = displayName
PathCategory.MENTAL_HEALTH = PathCategory("Mental health focus")
PathCategory.STRENGTH = PathCategory("Strength & bone health")
PathCategory.FULL_BODY = PathCategory("Full body health")
PathCategory.LEARNING = PathCategory("Learning")
PathCategory.SELF_DIRECTED = PathCategory("Self-directed")
PathCategory.MENTAL_HEALTH.name = "MENTAL_HEALTH"
PathCategory.MENTAL_HEALTH.ordinal = 0
PathCategory.STRENGTH.name = "STRENGTH"
PathCategory.STRENGTH.ordinal = 1
PathCategory.FULL_BODY.name = "FULL_BODY"
PathCategory.FULL_BODY.ordinal = 2
PathCategory.LEARNING.name = "LEARNING"
PathCategory.LEARNING.ordinal = 3
PathCategory.SELF_DIRECTED.name = "SELF_DIRECTED"
PathCategory.SELF_DIRECTED.ordinal = 4
PathCategory._entries = KtList([PathCategory.MENTAL_HEALTH, PathCategory.STRENGTH, PathCategory.FULL_BODY, PathCategory.LEARNING, PathCategory.SELF_DIRECTED])
PathCategory.values = staticmethod(lambda: PathCategory._entries)
PathCategory.entries = PathCategory._entries
PathCategory.valueOf = staticmethod(lambda s: next(e for e in PathCategory._entries if e.name == s))


class PathDefinition:
    """≡KT  data class PathDefinition  -> data class (exact)
    attrs (18/18): hasCustomName, repRangeMax, repRangeMin, category, educationalCopy, modalityNotes, targetMinutesPerSession, maxSessionsPerWeek, minSessionsPerWeek, citations, evidenceSummary, focusAreas, goalType, tagline, name, id, primaryLever, secondaryLever
    connects(1deg): FocusArea, GoalType, PathCategory, PathLever
    """
    def __init__(self, id, name, tagline, goalType, focusAreas, evidenceSummary, citations, minSessionsPerWeek, maxSessionsPerWeek, targetMinutesPerSession, modalityNotes, educationalCopy, category, repRangeMin, repRangeMax, hasCustomName=False):
        self.id = id
        self.name = name
        self.tagline = tagline
        self.goalType = goalType
        self.focusAreas = focusAreas
        self.evidenceSummary = evidenceSummary
        self.citations = citations
        self.minSessionsPerWeek = minSessionsPerWeek
        self.maxSessionsPerWeek = maxSessionsPerWeek
        self.targetMinutesPerSession = targetMinutesPerSession
        self.modalityNotes = modalityNotes
        self.educationalCopy = educationalCopy
        self.category = category
        self.repRangeMin = repRangeMin
        self.repRangeMax = repRangeMax
        self.hasCustomName = hasCustomName
    @property
    def primaryLever(self):
        return ((LEVER_EMPHASIS[self.id] if LEVER_EMPHASIS[self.id] is not None else DEFAULT_LEVERS))[0]
    @property
    def secondaryLever(self):
        return ((LEVER_EMPHASIS[self.id] if LEVER_EMPHASIS[self.id] is not None else DEFAULT_LEVERS))[1]
    DEFAULT_LEVERS = (PathLever.VOLUME, PathLever.EXERCISE_ROTATION)
    LEVER_EMPHASIS = mapOf(("path_just_show_up", ((PathLever.EXERCISE_ROTATION, PathLever.VOLUME))), ("path_balanced_fitness", ((PathLever.VOLUME, PathLever.EXERCISE_ROTATION))), ("path_moving_through", ((PathLever.EXERCISE_ROTATION, PathLever.VOLUME))), ("path_anxiety_movers", ((PathLever.EXERCISE_ROTATION, PathLever.VOLUME))), ("path_bone_builders", ((PathLever.RIR, PathLever.VOLUME))), ("path_brain_builders", ((PathLever.EXERCISE_ROTATION, PathLever.VOLUME))), ("path_stronger_after", ((PathLever.VOLUME, PathLever.RIR))), ("path_self_directed", ((PathLever.INTENSITY, PathLever.VOLUME))), ("path_ground_up", ((PathLever.EXERCISE_ROTATION, PathLever.RIR))), ("path_learn_to_listen", ((PathLever.EXERCISE_ROTATION, PathLever.RIR))))
    @staticmethod
    def grouped(excludeIds=emptySet()):
        def _lam1(category):
            paths = PathDefinition.ALL.filter((lambda it=None: it.category == self.category and (it.id not in excludeIds)))
            return (None if (len(paths) == 0) else (self.category, paths))
        return PathCategory.entries.mapNotNull(_lam1)
    @staticmethod
    def findById(id):
        return PathDefinition.ALL.find((lambda it=None: it.id == id))
    @staticmethod
    def combinedRepRange(pathIds):
        ranges = pathIds.mapNotNull((lambda it=None: PathDefinition.findById(it))).map((lambda it=None: KtList(range(it.repRangeMin, it.repRangeMax + 1))))
        if (len(ranges) == 0):
            return None
        lo = ranges.maxOf((lambda it=None: it[0]))
        hi = ranges.minOf((lambda it=None: it[-1]))
        return (KtList(range(lo, hi + 1)) if lo <= hi else KtList(range(ranges.minOf((lambda it=None: it[0])), ranges.maxOf((lambda it=None: it[-1])) + 1)))


PathDefinition.ALL = listOf(PathDefinition(id="path_just_show_up", name="Just Show Up", tagline="Any workout beats no workout.", goalType=GoalType.GENERAL_FITNESS, focusAreas=listOf(FocusArea.CONSISTENCY), evidenceSummary="Adherence is the strongest independent predictor of long-term fitness outcomes across every population studied. The dose-response curve for exercise is steepest at the low end — moving from zero to 2–3 sessions/week produces the largest per-session return, and real mortality benefit exists BELOW the 150 min/week guideline (HR ≈ 0.80 for sub-guideline activity). There is no minimum intensity threshold for adherence-driven health benefits (walking-cadence intensity is not independently tied to mortality). For muscle-strengthening specifically, mortality benefit follows a J-curve peaking at ~30–60 min/week (≈10–17% lower all-cause mortality) — more is not necessarily better. Protocol target: 3 sessions/week, 25–40 min, RPE 5–7 (moderate effort). 3 sets × 10–15 reps per exercise, rest 60–90 s. Progressive overload: add 1 rep per session before increasing load.", citations=listOf("Momma et al. (2022). Muscle-strengthening activities are associated with lower risk and mortality in major non-communicable diseases: a systematic review and meta-analysis. British Journal of Sports Medicine. [PMID 35228201; J-curve, ~30–60 min/wk sweet spot]", "Saint-Maurice et al. (2020). Association of Daily Step Count and Step Intensity With Mortality Among US Adults. JAMA. [8,000 vs 4,000 steps/day = ~51% lower mortality; step intensity not independently associated]", "Arem et al. (2015). Leisure Time Physical Activity and Mortality: A Detailed Pooled Analysis of the Dose-Response Relationship. JAMA Internal Medicine. [benefit below guideline; no upper-end harm]", "Warburton et al. (2006). Health benefits of physical activity: the evidence. CMAJ."), minSessionsPerWeek=2, maxSessionsPerWeek=7, targetMinutesPerSession=30, modalityNotes="Any modality at RPE 5–7 (conversation possible but slightly laboured). 3 sets × 10–15 reps is a suitable default. Rest 60–90 s between sets. Progressive overload: add 1 rep per session when all sets feel at RPE ≤ 7; increase weight only when you've reached the top of the rep range on all sets. On low-energy days, do less — not nothing.", educationalCopy="The health benefits of exercise are not gated by optimal programming. The biggest return on investment is between zero and 2 sessions/week. Consistency — showing up for months and years — outperforms any single protocol. This path tracks adherence, not performance. The sample program attached to this path is intentionally moderate: full-body, 3 days/week, achievable without leaving you drained. When you feel good, add reps. When you feel off, reduce load and still show up.", category=PathCategory.FULL_BODY, repRangeMin=10, repRangeMax=15), PathDefinition(id="path_balanced_fitness", name="Balanced Fitness", tagline="A little of everything, done well — strong, conditioned, and mobile.", goalType=GoalType.GENERAL_FITNESS, focusAreas=listOf(FocusArea.GENERAL_FITNESS), evidenceSummary="Balanced general fitness — strength, conditioning, and mobility together — is the WHO/ACSM consensus prescription: 150–300 min/week of moderate aerobic activity (or 75–150 vigorous) PLUS muscle-strengthening of all major muscle groups on 2+ days/week. The general-health benefit is well-established and begins below the guideline (mortality benefit at sub-150 min/wk; no intensity floor), with muscle-strengthening adding a further ~10–17% mortality reduction at ~30–60 min/week (verified 2026-06-14: Momma 2022; Saint-Maurice 2020; Arem 2015). Unlike the adherence-first Just Show Up path, this path assumes you already show up and want to progress: structured progressive overload across mixed modalities. Protocol: 3–4×/week, 40–50 min, RPE 6–8, resistance 2–3×/week (8–15 reps, double progression) + conditioning toward the weekly aerobic target + brief mobility.", citations=listOf("World Health Organization (2020). WHO Guidelines on physical activity and sedentary behaviour. [150–300 min/wk moderate aerobic + muscle-strengthening of all major groups on 2+ days/wk]", "Garber et al. (2011). ACSM Position Stand: Quantity and Quality of Exercise for Developing and Maintaining Fitness. Medicine & Science in Sports & Exercise. [the balanced FITT-VP recommendation across aerobic, resistance, and flexibility]", "Momma et al. (2022). Muscle-strengthening activities and mortality. British Journal of Sports Medicine. [~30–60 min/wk strength sweet spot; verified 2026-06-14]", "Warburton et al. (2006). Health benefits of physical activity: the evidence. CMAJ."), minSessionsPerWeek=3, maxSessionsPerWeek=5, targetMinutesPerSession=45, modalityNotes="A deliberate blend, not a single modality: 2–3 resistance sessions/week (compound-led, 8–15 reps at RPE 6–8, double progression) + conditioning toward 150+ min/week of moderate aerobic work + brief mobility (a few 30–60 s holds for tight areas, or full-ROM lifting). Progress for real — add reps to the top of the range, then add load. This path is for someone who is already consistent and wants to be well-rounded and capable, not chasing a single number.", educationalCopy="This is the generalist's path: broadly fit — strong enough, conditioned enough, mobile enough — with no single goal dominating. The evidence for general health is some of the strongest in all of exercise science, and the dose is the familiar public-health prescription: move most days, lift twice a week, keep a little mobility. It differs from Just Show Up in intent — Just Show Up is about building the habit when showing up is the hard part; Balanced Fitness assumes the habit is there and adds structure and progression so you actually get fitter over time. The attached programs blend strength and conditioning rather than specialising in one.", category=PathCategory.FULL_BODY, repRangeMin=8, repRangeMax=15), PathDefinition(id="path_moving_through", name="Moving Through", tagline="Exercise is one of the most evidence-backed interventions for depression.", goalType=GoalType.MENTAL_HEALTH, focusAreas=listOf(FocusArea.MENTAL_EMOTIONAL), evidenceSummary="Multiple meta-analyses confirm exercise is equivalent to antidepressants for mild-to-moderate depression when delivered at the evidence-supported dose: 150–200 min/week of moderate-intensity activity across 3 sessions. Resistance training shows robust effects on mood, self-efficacy, and functional self-concept — comparable to aerobic exercise. Protocol: 3×/week, 40–50 min, RPE 5–7, 3 sets × 10–15 reps, rest 60–90 s. Progressive overload is gradual (~5% per 2 weeks). Adherence matters more than intensity.", citations=listOf("Heissel et al. (2023). Exercise as medicine for depressive symptoms? A systematic review and meta-analysis with meta-regression. British Journal of Sports Medicine 57(16):1049. [41 RCTs; SMD −0.95; NNT 2; recommends supervised, moderate-intensity, predominantly aerobic regimes]", "Noetel et al. (2024). Effect of exercise for depression: systematic review and network meta-analysis of randomised controlled trials. BMJ 384:e075847. [218 RCTs / 14,170; strength training g=−0.49, behind walking/jogging and yoga]", "Kvam et al. (2016). Exercise as a treatment for depression: a meta-analysis. Journal of Affective Disorders. [g=0.68; not significantly different from medication or psychotherapy]", "Gómez-García et al. (2024). Effects of strength training on depression: systematic review and meta-analysis. Psychiatry Research. [strength training SMD=−0.51]", "Blumenthal et al. (2007). Exercise and pharmacotherapy in the treatment of major depressive disorder. Psychosomatic Medicine."), minSessionsPerWeek=3, maxSessionsPerWeek=5, targetMinutesPerSession=50, modalityNotes="Resistance training 3×/week, 40–50 min, RPE 5–7. 3 working sets × 10–15 reps, rest 60–90 s. Do not chase intensity — moderate effort shows the most consistent mood effects across the literature. Progressive overload: add 1 rep/session; increase weight by 1–2.5 kg only when all sets are completed at RPE ≤ 6. If motivation is low, reduce sets or load and still show up — the act of training matters independently of volume.", educationalCopy="Exercise acts on depression through multiple pathways: BDNF upregulation supporting neuroplasticity, HPA axis down-regulation reducing cortisol reactivity, reduced neuroinflammation (IL-6, TNF-α), and monoamine effects similar in mechanism to SSRIs. The psychological pathways — mastery, routine, self-efficacy, identity — are equally significant. The evidence-supported dose is 150–200 min/week. Showing up three times is the intervention. The specific exercises matter less than the consistent application.", category=PathCategory.MENTAL_HEALTH, repRangeMin=10, repRangeMax=15), PathDefinition(id="path_anxiety_movers", name="Anxiety Movers", tagline="Movement rewires the anxiety response.", goalType=GoalType.MENTAL_HEALTH, focusAreas=listOf(FocusArea.MENTAL_EMOTIONAL), evidenceSummary="Regular moderate-intensity exercise reduces trait anxiety and improves tolerance of anxiety symptoms. Resistance training and moderate-intensity aerobic exercise both show significant effect sizes. Key protocol note: high-intensity intervals may temporarily increase anxiety in sensitive individuals during early training. No RCT-grade dose-response exists, so frequency is set conservatively from the best available trial: 2–3×/week, 30–40 min, RPE 5–7, 2–3 sets × 8–12 reps (the strongest RT trial achieved a large effect at just 2×/week). Rest 90–120 s between sets (intentionally longer to keep in-session arousal moderate). Progressive overload: maximum 5% load increase per week — conservative by design.", citations=listOf("Stonerock et al. (2015). Exercise as treatment for anxiety: systematic review and analysis. Annals of Behavioral Medicine. [12 RCTs + 5 meta-analyses; NO RCT compared intensities — no dose-response established; remains the standing gap statement]", "Gordon, LeBouthillier et al. (2020). Resistance exercise training for anxiety and worry symptoms among young adults: a randomized controlled trial. Scientific Reports 10:17548. [2×/week × 8 wk, 2×8–12 reps, RPE 14/20; large effect d=0.85]", "Herring et al. (2010). The effect of exercise training on anxiety symptoms among patients. Archives of Internal Medicine.", "Asmundson et al. (2013). Let's get physical: a contemporary review of the anxiolytic effects of exercise for anxiety and its disorders. Depression and Anxiety."), minSessionsPerWeek=2, maxSessionsPerWeek=3, targetMinutesPerSession=35, modalityNotes="Resistance training or moderate-intensity cardio at RPE 5–7. 2–3 sets × 8–12 reps, rest 90–120 s. Longer rest periods are intentional — they keep heart rate moderate between sets, reducing in-session physiological arousal. Avoid very high-intensity intervals in the first 6–8 weeks. Progressive overload: increase weight only when RPE drops below 5 on all sets. Prioritise consistency over progression.", educationalCopy="Exercise reduces anxiety by down-regulating the HPA stress axis (lowering cortisol and adrenaline baseline), improving interoceptive accuracy (correctly labelling physical sensations as exertion rather than threat), and providing repeated safe exposure to physical arousal. Over time, your nervous system learns that elevated heart rate, breathing, and body temperature are normal and controllable — not signs of danger. The key is moderate intensity and consistency. The attached program uses compound movements at manageable loads, designed to build confidence in the body without overwhelming the nervous system.", category=PathCategory.MENTAL_HEALTH, repRangeMin=8, repRangeMax=12), PathDefinition(id="path_bone_builders", name="Bone Builders", tagline="Load your bones to keep them.", goalType=GoalType.BONE_HEALTH, focusAreas=listOf(FocusArea.PHYSICAL_STRENGTH), evidenceSummary="Progressive resistance training is one of the only interventions proven to increase bone mineral density in adults. Bone requires mechanical strain above a minimum threshold — approximately 70–85% 1RM (RPE 8–9) — to stimulate osteoblast activity. Effects are site-specific: hip-dominant movements build hip and lumbar spine density; upper-body work builds shoulder girdle and radius. Protocol: 3×/week, 4 sets × 5–8 reps at RPE 8–9, rest 120–180 s. Progressive overload is load-first: increase weight before adding sets or reps.", citations=listOf("Layne & Nelson (1999). The effects of progressive resistance training on bone density. Medicine & Science in Sports & Exercise.", "Kohrt et al. (2004). Physical activity and bone health. Medicine & Science in Sports & Exercise.", "Guadalupe-Grau et al. (2009). Exercise and bone mass in adults. Sports Medicine.", "Watson et al. (2018). High-Intensity Resistance and Impact Training Improves Bone Mineral Density and Physical Function in Postmenopausal Women with Osteopenia and Osteoporosis: The LIFTMOR RCT. Journal of Bone and Mineral Research 33(2):211–220. [2×/wk, 30 min, 5×5 >85% 1RM + impact, ~8 mo → lumbar spine +2.9% vs −1.2%. Verified 2026-06-14 — this is a validated PRESCRIPTION, not a proven minimum strain threshold; 2×/wk is the minimum tested]", "Shojaa, Kemmler et al. (2023). Effects of dynamic resistance exercise on bone mineral density in postmenopausal women: a systematic review and meta-analysis with special emphasis on exercise parameters. Osteoporosis International 34:1145–1178. [80 studies / 5,581; site-specific: total hip SMD 0.41 > lumbar spine 0.29 > femoral neck 0.27]"), minSessionsPerWeek=2, maxSessionsPerWeek=4, targetMinutesPerSession=50, modalityNotes="Progressive resistance training is mandatory — swimming and cycling do not produce adequate bone strain. 4 working sets × 5–8 reps at RPE 8–9 (70–85% 1RM). Rest 120–180 s. Priority movements: bilateral hip hinge (deadlift, hip thrust) for hip and lumbar density; squat pattern for spine and hip; horizontal row for upper spine and shoulder girdle; overhead press for shoulder girdle and upper spine. Progressive overload: load-first — increase weight by 2.5–5% per session when all sets completed at RPE ≤ 8.", educationalCopy="Bone mineral density responds to mechanical strain above a threshold — Wolff's Law. The strain must be sufficiently high (70–85% of 1RM), applied repeatedly, and progressive over months and years. Bone adapts slowly: measurable DXA changes take 6–12 months of consistent training. What you're tracking is the input, not the output. The three most important loaded sites clinically are the femoral neck (hip), lumbar spine (L2–L4), and distal radius — all covered by the compound movements in this program. Load-first progression means adding weight takes priority over adding reps or sets.", category=PathCategory.STRENGTH, repRangeMin=5, repRangeMax=8), PathDefinition(id="path_brain_builders", name="Brain Builders", tagline="Resistance training builds brain, not just muscle.", goalType=GoalType.BRAIN_HEALTH, focusAreas=listOf(FocusArea.BRAIN_COGNITIVE), evidenceSummary="Progressive resistance training improves global cognition — RT ranks as the top single exercise modality for overall cognitive function in recent network meta-analyses (SMD ≈ 0.55), with a clear effect on inhibitory control. Note: the executive-function-specific benefit is contested (some 2025 meta-analyses find it null), and RT is not the strongest modality for memory. Both 1×/week and 2×/week are effective and heavy load is not required. Protocol: 2–3×/week, 45–60 min, 3–4 sets × 8–12 reps, RPE 7–8, rest 90–120 s. Time-to-effect is slow: measurable gains in older-adult RCTs took ~6–12 months (not weeks). Evidence base is predominantly older adults (60+); benefit for younger users is inferred, not tested.", citations=listOf("Frontiers in Aging Neuroscience (2025). Network meta-analysis of exercise modalities for cognition in older adults — resistance training ranked highest for global cognition (SMD ≈ 0.55). doi:10.3389/fnagi.2025.1510773.", "Liu-Ambrose et al. (2010). Resistance training and executive functions: a 12-month randomized controlled trial. Archives of Internal Medicine. [12 mo; both 1×/wk and 2×/wk effective; no benefit at the 6-mo interim — time-to-effect is months, not weeks]", "Northey et al. (2018). Exercise interventions for cognitive function in adults older than 50: a systematic review with meta-analysis. British Journal of Sports Medicine.", "2025 meta-analysis (PMC12772445) — RT significant for overall cognition and working memory but NOT executive function/processing speed; basis for flagging the EF-specific claim as contested."), minSessionsPerWeek=2, maxSessionsPerWeek=3, targetMinutesPerSession=50, modalityNotes="Progressive resistance training 2–3×/week, 45–60 min, RPE 7–8. 3–4 sets × 8–12 reps, rest 90–120 s. Deliberate exercise selection: include unilateral movements (single-leg deadlift, split squat, single-leg hip thrust) and novel coordination patterns (windmill, landmine row) to maximise neural recruitment. Progressive overload: increase load when all sets completed at RPE ≤ 7; also progress exercise complexity over time by introducing more demanding movement variations.", educationalCopy="Resistance training benefits the brain through BDNF (brain-derived neurotrophic factor) upregulation, increased cerebral blood flow, reduced neuroinflammation, and IGF-1 signalling supporting neuroplasticity and hippocampal neurogenesis. In recent network meta-analyses, resistance training is the most effective single exercise modality for overall cognition — though its specific effect on executive function is debated, and the gains are slow, accruing over months rather than weeks. Even one session a week shows measurable benefit in trials; two is a sensible target. Unilateral and coordination-intensive exercises are included as a mechanistic bet on extra neural challenge (interlimb coordination, proprioception, motor learning) — plausible, but not yet proven to beat standard lifting for cognition.", category=PathCategory.MENTAL_HEALTH, repRangeMin=8, repRangeMax=12), PathDefinition(id="path_stronger_after", name="Stronger After ___", tagline="Rebuild from where you are.", goalType=GoalType.REHABILITATION, focusAreas=listOf(FocusArea.PHYSICAL_STRENGTH), evidenceSummary="After injury, surgery, or illness, progressive resistance loading is the primary evidence-backed intervention for restoring capacity. For tendinopathy specifically, heavy-slow-resistance and eccentric loading beat passive/rest treatment with durable (52-week) gains, and continued loading is as safe as rest when guided by a pain-monitoring model (HIGH confidence: Silbernagel 2007, Beyer 2015, Kongsgaard 2009). Progression is gated by PAIN RESPONSE, not a fixed weekly percentage — the popular '10%/week' rule is contested and the acute:chronic workload ratio is formally discredited (Impellizzeri 2020); neither should be encoded as a threshold. Pain-monitoring rule: pain up to a set threshold during/after loading is acceptable ONLY IF it settles to baseline by the next morning AND does not increase week-to-week. For this deliberately gentle path the conservative ≤3/10 (abating within hours) is the default; ≤5/10-over-24h is the documented permissive ceiling. Protocol: 3×/week, start RPE 5–6 and progress toward 7–8 as the pain criteria allow, rest 90–120 s; slow tempos and isometric holds are useful early for analgesia. SCOPE: the strong evidence is tendinopathy-specific (Achilles/patellar) — post-surgical, ligament, bone, and postpartum return are extrapolation.", citations=listOf("Silbernagel et al. (2007). Continued sports activity, using a pain-monitoring model, during rehabilitation in patients with Achilles tendinopathy: a randomized controlled trial. American Journal of Sports Medicine. [Level-1 RCT, n=38; the pain-monitoring model — ≤5/10, settle by next morning, no week-to-week escalation; continued loading as safe as rest]", "Beyer et al. (2015). Heavy slow resistance versus eccentric training as treatment for Achilles tendinopathy: a randomized controlled trial. American Journal of Sports Medicine. [Level-1 RCT, n=58; HSR = eccentric, both effective, maintained at 52 wk]", "Kongsgaard et al. (2009). Corticosteroid injections, eccentric decline squat training and heavy slow resistance training in patellar tendinopathy. Scandinavian Journal of Medicine & Science in Sports. [HSR good short- AND long-term; injection deteriorates long-term]", "Cook & Purdam (2009). Is tendon pathology a continuum? British Journal of Sports Medicine. [continuum model — confirmed, refined not refuted by Cook 2016; qualitative direction, not numeric thresholds]", "Impellizzeri et al. (2020). Acute:chronic workload ratio: conceptual and methodological issues. Int J Sports Physiology & Performance. [ACWR not evidence-based for load-management/injury thresholds — basis for NOT encoding ACWR or a hard 10%/wk rule]"), minSessionsPerWeek=2, maxSessionsPerWeek=4, targetMinutesPerSession=40, modalityNotes="Start at RPE 5–6 (manageable) and progress toward RPE 7–8 only as the pain-monitoring criteria allow. Rest 90–120 s. PAIN-MONITORING MODEL — the progression gate, not a fixed weekly %: pain during and right after loading may reach ≤3/10 (conservative default; the validated permissive ceiling is ≤5/10), PROVIDED it (1) settles back to baseline by the next morning and (2) does not climb week to week. If it doesn't settle, reduce load next session. Do NOT progress by a fixed '10%/week' or a workload-ratio target — neither is evidence-based. Slow tempos (e.g. 3 s down / 3 s up) and isometric holds help early for pain control. Never skip recovery days. Works best when cleared for resistance training by a healthcare provider.", educationalCopy="Recovery is not the absence of training — it's structured, progressive loading that respects tissue healing timelines. Muscle recovers in 6–8 weeks. Tendons and ligaments take 3–6 months. Bone takes 6–12 months. This creates vulnerability windows where muscles can tolerate loads that connective tissue cannot. Conservative load progression through these windows is not weakness — it is the standard of care across sports medicine. This path tracks adherence to that protocol. Show up, load gradually, let the cascade of adaptation happen on its own timeline.", category=PathCategory.STRENGTH, repRangeMin=8, repRangeMax=12, hasCustomName=True), PathDefinition(id="path_self_directed", name="On my own journey", tagline="You know your goals. We'll get out of your way. Only recommended for experienced lifters who want to do their own programming.", goalType=GoalType.GENERAL_FITNESS, focusAreas=listOf(FocusArea.SELF_DIRECTED), evidenceSummary="Evidence-based principles apply regardless of goal. Strength: 3–5 sets × 3–6 reps at RPE 8–9, rest 3–5 min, 2–3×/week per muscle group. Hypertrophy: 3–5 sets × 6–15 reps at RPE 7–8, rest 1–3 min, 10–20 sets/muscle group/week. General fitness: 3 sets × 10–15 reps at RPE 6–7, rest 60–90 s. Progressive overload via double progression: increase reps to top of target range across all sets, then increase weight by 2.5–5 kg. Minimum effective volume: ~10 sets/muscle group/week. Maximum adaptive volume: ~20 sets/week before recovery becomes limiting.", citations=listOf("Kraemer & Ratamess (2004). Fundamentals of resistance training: progression and exercise prescription. Medicine & Science in Sports & Exercise.", "Schoenfeld et al. (2017). Dose-response relationship between weekly resistance training volume and increases in muscle mass. Journal of Sports Sciences.", "Krieger JW (2010). Single vs. multiple sets of resistance exercise for muscle hypertrophy: a meta-analysis. Journal of Strength and Conditioning Research.", "Grgic et al. (2019). Effect of resistance training frequency on gains in muscular strength: a systematic review and meta-analysis. Sports Medicine."), minSessionsPerWeek=2, maxSessionsPerWeek=6, targetMinutesPerSession=60, modalityNotes="Set your own frequency (3–6×/week) and structure (full-body, upper/lower, PPL, or any split). Apply double progression: increase reps each session until you hit the top of your target range with all sets, then increase weight by 2.5–5 kg and reset reps. Volume guidelines: 10–15 sets/muscle group/week for maintenance and moderate growth; 15–20 sets/week for accelerated hypertrophy. Deload every 4–8 weeks: reduce volume by 40–50% for one week.", educationalCopy="The fundamentals of effective resistance training are load-agnostic: progressive overload over time, sufficient volume (10–20 sets/muscle/week), adequate frequency (2–4×/week per muscle group), and consistent recovery. These principles apply whether you're training for powerlifting, aesthetics, sport performance, or general health. The best program is one you'll follow and make progress on. The sample program attached is a 4-day upper/lower split built for intermediate lifters — compound primary lifts with accessory work, and sensible superset pairings to keep session time under 60 minutes.", category=PathCategory.SELF_DIRECTED, repRangeMin=3, repRangeMax=15), PathDefinition(id="path_ground_up", name="Ground Up", tagline="Learn the craft of training, from the ground up.", goalType=GoalType.GENERAL_FITNESS, focusAreas=listOf(FocusArea.PHYSICAL_STRENGTH, FocusArea.CONSISTENCY), evidenceSummary="A structured apprenticeship for newer lifters: build the movement skill, work capacity, and autoregulation literacy that every later goal depends on. Progresses from full-body general training into strength, walking the user across experience levels. Protocol: 3–4×/week, reps 3–12 (movement-dependent), RPE capped at 9, with linear then double progression as competence grows. Graduation routes to self-directed programming.", citations=listOf("Rippetoe & Baker (2013). Practical Programming for Strength Training. The Aasgaard Company.", "Helms et al. (2016). Application of the Repetitions in Reserve-Based RPE Scale for Resistance Training. Sports Medicine.", "Suchomel et al. (2018). The Importance of Muscular Strength: Training Considerations. Sports Medicine."), minSessionsPerWeek=3, maxSessionsPerWeek=4, targetMinutesPerSession=45, modalityNotes="3–4×/week. Reps 3–12 depending on the lift and phase; RPE never above 9 while skill is still developing. Master the compound patterns first, then add load. Progression is linear early (add weight each week), shifting to double progression as you advance. Movements are equipment-neutral — the app substitutes by what you have.", educationalCopy="Ground Up is the learn-the-craft path. Rather than optimising a single goal, it teaches you how training itself works — movement quality, progressive overload, reading your own effort — across a multi-phase plan that takes you from foundations into real strength. It is the natural companion to Learn to Listen. When you graduate, you'll have the literacy to run your own programming on the On my own journey path.", category=PathCategory.LEARNING, repRangeMin=3, repRangeMax=12), PathDefinition(id="path_learn_to_listen", name="Learn to Listen", tagline="Capacity over outcome. Hear and respond to your body's signals.", goalType=GoalType.BODY_AWARENESS, focusAreas=listOf(FocusArea.BODY_AWARENESS, FocusArea.MENTAL_EMOTIONAL), evidenceSummary="Body awareness (interoceptive accuracy) is the foundational skill for all sustainable training. Research shows that new lifters consistently overestimate how close they are to failure. Learning to accurately perceive Reps in Reserve (RIR) and muscle activation allows for precise autoregulation and prevents injury. Protocol: 3-4×/week, focused practice on movement quality and effort perception. Graduation: RIR estimates accurate within 1 rep 85% of the time.", citations=listOf("Helms et al. (2016). Application of the Repetitions in Reserve-Based Rating of Perceived Exertion Scale for Resistance Training. Sports Medicine.", "Zourdos et al. (2016). Novel Resistance Training-Specific Rating of Perceived Exertion Scale Measuring Repetitions in Reserve. Journal of Strength and Conditioning Research.", "Mehling et al. (2012). The Multidimensional Assessment of Interoceptive Awareness (MAIA). PLoS ONE."), minSessionsPerWeek=3, maxSessionsPerWeek=4, targetMinutesPerSession=40, modalityNotes="Focus on movement quality, breathing, and muscle activation. 3-4 sets × 8-12 reps. Rest 90-120 s. Use safe, controlled movements to explore proximity to failure. This path is less about load and more about the quality of the signal between your brain and your body.", educationalCopy="Learn to Listen is the one path about capacity rather than outcome. It makes you a better user of your own body. You'll move through a curriculum starting with basic gym movements, then RIR calibration, then breath work and muscle activation. Completing this path unlocks more accurate autoregulation everywhere else in the app. It is strongly recommended for all new and returning lifters.", category=PathCategory.LEARNING, repRangeMin=8, repRangeMax=12))
